import { moduleMetadata } from '@storybook/angular';
import { PfAuthLoginComponent } from './auth-login.component';
const meta = {
    title: 'Composants fonctionnels/AuthLogin',
    component: PfAuthLoginComponent,
    tags: ['autodocs'],
    parameters: {
        layout: 'fullscreen',
        docs: {
            description: {
                component: "Mire d'authentification - écran `login.ftl` Keycloak. Composant de référence design uniquement (cf. décision K.1).",
            },
        },
    },
    decorators: [moduleMetadata({ imports: [PfAuthLoginComponent] })],
    args: { appName: 'Démarches en ligne' },
    render: (args) => ({
        props: args,
        template: `<pf-auth-login
      [appName]="appName"
      [identifierLabel]="identifierLabel || 'Identifiant'"
      [identifierType]="identifierType || 'text'"
      [errorMessage]="errorMessage || ''"
      [loading]="loading || false"
      [showForgotPassword]="showForgotPassword !== false"
      [showRegister]="showRegister !== false"
    ></pf-auth-login>`,
    }),
};
export default meta;
export const Default = {};
export const WithEmail = {
    args: { identifierLabel: 'Adresse email', identifierType: 'email' },
};
export const WithError = {
    args: { errorMessage: 'Identifiant ou mot de passe incorrect.' },
};
export const Loading = {
    args: { loading: true },
};
export const RegisterDisabled = {
    args: { showRegister: false, appName: 'Espace agent (interne)' },
};
export const MinimalApp = {
    args: { appName: '', showRegister: false, showForgotPassword: false },
};
